{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "1\n2\n3\n",
      "output": "6\n",
      "notes": "Basic case to validate simple addition."
    },
    {
      "name": "negative_numbers",
      "input": "-1\n-2\n-3\n",
      "output": "-6\n",
      "notes": "Tests handling of negative numbers."
    },
    {
      "name": "zero_case",
      "input": "0\n0\n0\n",
      "output": "0\n",
      "notes": "Edge case with all zeros."
    },
    {
      "name": "large_numbers",
      "input": "1000000\n2000000\n3000000\n",
      "output": "6000000\n",
      "notes": "Tests handling of large integers."
    },
    {
      "name": "mixed_numbers",
      "input": "-1\n0\n1\n",
      "output": "0\n",
      "notes": "Tests mixed positive and negative numbers."
    },
    {
      "name": "single_input",
      "input": "5\n",
      "output": "5\n",
      "notes": "Tests behavior with a single input."
    },
    {
      "name": "multiple_zeros",
      "input": "0\n0\n0\n0\n0\n",
      "output": "0\n",
      "notes": "Tests multiple zeros to ensure consistent output."
    },
    {
      "name": "large_negative_numbers",
      "input": "-1000000\n-2000000\n-3000000\n",
      "output": "-6000000\n",
      "notes": "Tests handling of large negative integers."
    }
  ],
  "assumptions": "Input will always be valid integers.",
  "notes": "Ensure to handle both positive and negative integers correctly."
}
